class MetadataStoreManager:
    def __init__(self, storage_path: str = "./metadata_store.json"):
        self.storage_path = storage_path
        self.store = {}
        self.load()

    def load(self):
        if os.path.exists(self.storage_path):
            try:
                with open(self.storage_path, "r", encoding="utf-8") as f:
                    self.store = json.load(f)
            except Exception:
                self.store = {}

    def save(self):
        with open(self.storage_path, "w", encoding="utf-8") as f:
            json.dump(self.store, f, indent=2)

    def add_metadata(self, chunk_hash: str, metadata: Dict[str, Any]):
        """
        Store per-chunk metadata keying by the chunk's content hash.
        """
        self.store[chunk_hash] = metadata
        self.save()

    def get_metadata(self, chunk_hash: str) -> Dict[str, Any]:
        """
        Get metadata by chunk hash.
        """
        return self.store.get(chunk_hash)

class KnowledgeGraphManager:
def build_from_chunks(self, chunks: List[Dict[str, Any]]):
        """
        Build the Knowledge Graph from parser/chunker output.
        Nodes: Functions, Classes, Files, Modules
        Edges: Calls, Imports, Inherits, Uses, Creates, Reads, Writes
        """
        for chunk in chunks:
            meta = chunk["metadata"]
            file_path = meta.get("file")
            class_name = meta.get("class")
            func_name = meta.get("function")
            language = meta.get("language")

            # 1. Add nodes
            if file_path:
                self.graph.add_node(file_path, type="File", language=language)

            if class_name:
                self.graph.add_node(class_name, type="Class")
                # Link Class to File
                self.graph.add_edge(class_name, file_path, type="Uses")

            if func_name:
                full_func_name = f"{class_name}.{func_name}" if class_name else func_name
                self.graph.add_node(full_func_name, type="Function")
                # Link Function to File
                self.graph.add_edge(full_func_name, file_path, type="Uses")
                if class_name:
                    # Link Function to Class
                    self.graph.add_edge(full_func_name, class_name, type="Uses")

            # 2. Add edges from dependencies
            deps = meta.get("dependencies", [])
            for dep in deps:
                target = dep.get("target")
                dep_type = dep.get("type") # imports, inherits, calls

                # Map to capitalized edge types matching the schema
                edge_type = dep_type.capitalize() if dep_type else "Uses"
                if edge_type not in ["Calls", "Imports", "Inherits", "Uses", "Creates", "Reads", "Writes"]:
                    edge_type = "Uses"

                # Determine source node
                if func_name:
                    source = f"{class_name}.{func_name}" if class_name else func_name
                elif class_name:
                    source = class_name
                else:
                    source = file_path

                if target:
                    if not self.graph.has_node(target):
                        if edge_type == "Imports":
                            self.graph.add_node(target, type="Module")
                        elif edge_type == "Inherits":
                            self.graph.add_node(target, type="Class")
                        else:
                            self.graph.add_node(target, type="Function")

                    self.graph.add_edge(source, target, type=edge_type)

def wilcoxon_test(
    system_scores: List[float],
    baseline_scores: List[float],
    alternative: str = "two-sided",
) -> Dict[str, Any]:
    """
    Wilcoxon signed-rank test: tests whether system_scores > baseline_scores.

    Paired test: system_scores[i] and baseline_scores[i] must be scores on
    the same query. This assumes the same dataset in the same order was used.

    Parameters
    ----------
    system_scores : list[float]
        Per-query metric scores for the system under test.
    baseline_scores : list[float]
        Per-query metric scores for the comparison baseline.
    alternative : str
        "two-sided", "greater", or "less".

    Returns
    -------
    dict with keys: statistic, p_value, significant (p < 0.05), alternative.
    Returns {"error": ...} if scipy is unavailable.
    """
    if len(system_scores) != len(baseline_scores):
        return {"error": "Length mismatch between system_scores and baseline_scores"}
    if not system_scores:
        return {"error": "Empty input"}

    try:
        from scipy.stats import wilcoxon as scipy_wilcoxon

        differences = [s - b for s, b in zip(system_scores, baseline_scores)]
        # Remove zero differences (wilcoxon undefined for ties)
        nonzero_diffs = [d for d in differences if d != 0]

        if not nonzero_diffs:
            return {
                "statistic": float("nan"),
                "p_value": 1.0,
                "significant": False,
                "alternative": alternative,
                "note": "All differences are zero — test undefined",
            }

        stat, p_value = scipy_wilcoxon(nonzero_diffs, alternative=alternative)
        return {
            "statistic": float(stat),
            "p_value": float(p_value),
            "significant": float(p_value) < 0.05,
            "alternative": alternative,
            "n_pairs": len(nonzero_diffs),
        }
    except ImportError:
        return {"error": "scipy not installed — cannot run Wilcoxon test"}
    except Exception as e:
        return {"error": str(e)}

