def interpret_cohens_d(d: float) -> str:
    """Return a human-readable interpretation of Cohen's d."""
    if math.isnan(d):
        return "undefined"
    abs_d = abs(d)
    if abs_d < 0.2:
        return "negligible"
    elif abs_d < 0.5:
        return "small"
    elif abs_d < 0.8:
        return "medium"
    else:
        return "large"

