    def __init__(self):
        self.subscriptions = {}

    def subscribe(self, data_key, callback):
        if data_key not in self.subscriptions:
            self.subscriptions[data_key] = [callback]
        else:
            self.subscriptions[data_key].append(callback)

    def unsubscribe(self, data_key, callback=None):
