class BaseSystem(RetrievalSystem):
    """
    Base class for all evaluated systems.

    Provides config loading, memory measurement stubs, and chunk normalization.
    Concrete systems override `retrieve()` and `answer()`.
    """

    def __init__(self, config_overrides: Dict[str, Any] = None):
        self.config_overrides = config_overrides or {}
        self.config = _load_config(self.config_overrides)

    def configuration(self) -> Dict[str, Any]:
        """Return the effective configuration (base config + overrides)."""
        return {
            "config_overrides": self.config_overrides,
            "embedding_model": self.config.get("embedding_model"),
            "reranker_model": self.config.get("reranker_model"),
            "retrieval": self.config.get("retrieval", {}),
            "chunking": self.config.get("chunking", {}),
        }

    def _normalize_chunks(self, raw_chunks: List[Dict[str, Any]]) -> List[RetrievedChunk]:
        """Normalize a list of raw chunk dicts to RetrievedChunk objects."""
        chunks = []
        for i, raw in enumerate(raw_chunks):
            chunk = _normalize_chunk(raw)
            chunk.rank = i + 1
            chunks.append(chunk)
        return chunks

def agent_node(state: AgentState) -> Dict[str, Any]:
    if state.get("error") == "Zero chunks retrieved":
        # Graceful fallback per requirements
        return {"answer": "No relevant context found in the repository."}
    elif state.get("error"):
        return {"answer": f"Retrieval error occurred: {state['error']}"}

    try:
        agent_name = state["agent"]
        chunks = state["retrieved_chunks"]

        if agent_name == "code_agent":
            ans = code_agent.run(state["question"], chunks)
        elif agent_name == "data_agent":
            ans = data_agent.run(state["question"], chunks)
        else:
            ans = reasoning_agent.run(state["question"], chunks)

        return {"answer": ans}
    except Exception as e:
        # Catch timeouts or other LLM exceptions
        return {"answer": f"LLM backend execution failed: {str(e)}"}

def query(payload: QueryPayload):
    question = payload.question

    try:
        ans = orchestrator.answer(question)

        # Read last log entry to extract metadata
        log_path = "./logs/query_logs.jsonl"
        agent = "unknown"
        latency = 0.0
        sources = []

        chunks = []
        if os.path.exists(log_path):
            try:
                with open(log_path, "r", encoding="utf-8") as f:
                    lines = f.readlines()
                if lines:
                    last_entry = json.loads(lines[-1])
                    if last_entry.get("question") == question:
                        agent = last_entry.get("agent", "unknown")
                        latency = last_entry.get("latency", 0.0)
                        # Extract source files and chunks
                        seen_files = set()
                        for c in last_entry.get("retrieved_chunks", []):
                            file_path = c.get("metadata", {}).get("file")
                            if file_path and file_path not in seen_files:
                                sources.append(file_path)
                                seen_files.add(file_path)
                        chunks = last_entry.get("retrieved_chunks", [])
            except Exception:
                pass

        return {
            "answer": ans,
            "agent": agent,
            "latency": latency,
            "sources": sources,
            "chunks": chunks
        }
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Query failed: {str(e)}")

def count_tokens(text: str) -> int:
    """
    Approximate token count using a fast regex tokenizer.
    Splits by words and non-whitespace punctuation.
    """
    if not text:
        return 0
    return len(re.findall(r'\w+|[^\w\s]', text))

