def verify_candidate(qa: dict, context: str) -> tuple[bool, str]:
    """Automated verification step to check answerability, hallucination, and source support."""
    prompt = f"""You are a strict QA auditor. Review the following Q&A pair against the provided context.

Context:
{context}

Q&A Pair:
Question: {qa['question']}
Answer: {qa['answer']}
Category: {qa['category']}
Sources: {qa['sources']}

Verify the following:
1. Question is answerable from retrieved chunks.
2. Answer does not hallucinate information outside retrieved context.
3. Source files actually support the answer.
4. Question belongs to the requested category.

Output ONLY a valid JSON object:
{{
  "pass": true or false,
  "reason": "Brief explanation if false, else 'pass'"
}}
Return ONLY the JSON. Do not include markdown formatting or backticks.
"""
    response_text = generate(prompt, model_key="reasoning_agent_model")
    try:
        if response_text.startswith("```json"):
            response_text = response_text[7:]
        if response_text.startswith("```"):
            response_text = response_text[3:]
        if response_text.endswith("```"):
            response_text = response_text[:-3]
        data = json.loads(response_text.strip())
        return data.get("pass", False), data.get("reason", "Failed to parse reasoning")
    except Exception:
        return False, "Failed to parse verification response"

class BM25System(BaseSystem):
    """
    BM25 sparse retrieval baseline.

    Indexes all AST-based chunks at warm_up time. Retrieves by BM25 score.
    Generation: reasoning_agent (same LLM as other baselines).
    """

    @property
def retrieve(self, question: str, top_k: int = 5) -> List[RetrievedChunk]:
        if not hasattr(self, "_bm25") or self._bm25 is None:
            self.warm_up()
        if self._bm25 is None:
            return []

        tokenized_query = question.lower().split()
        scores = self._bm25.get_scores(tokenized_query)

        # Get top-k indices
        import numpy as np
        top_indices = np.argsort(scores)[::-1][:top_k]

        chunks = []
        for i, idx in enumerate(top_indices):
            raw_chunk = self._all_chunks[idx]
            chunks.append({
                "content": raw_chunk["content"],
                "metadata": raw_chunk["metadata"],
                "score": float(scores[idx]),
            })

        return self._normalize_chunks(chunks)

class KnowledgeGraphManager:
def build_from_chunks(self, chunks: List[Dict[str, Any]]):
        """
        Build the Knowledge Graph from parser/chunker output.
        Nodes: Functions, Classes, Files, Modules
        Edges: Calls, Imports, Inherits, Uses, Creates, Reads, Writes
        """
        for chunk in chunks:
            meta = chunk["metadata"]
            file_path = meta.get("file")
            class_name = meta.get("class")
            func_name = meta.get("function")
            language = meta.get("language")

            # 1. Add nodes
            if file_path:
                self.graph.add_node(file_path, type="File", language=language)

            if class_name:
                self.graph.add_node(class_name, type="Class")
                # Link Class to File
                self.graph.add_edge(class_name, file_path, type="Uses")

            if func_name:
                full_func_name = f"{class_name}.{func_name}" if class_name else func_name
                self.graph.add_node(full_func_name, type="Function")
                # Link Function to File
                self.graph.add_edge(full_func_name, file_path, type="Uses")
                if class_name:
                    # Link Function to Class
                    self.graph.add_edge(full_func_name, class_name, type="Uses")

            # 2. Add edges from dependencies
            deps = meta.get("dependencies", [])
            for dep in deps:
                target = dep.get("target")
                dep_type = dep.get("type") # imports, inherits, calls

                # Map to capitalized edge types matching the schema
                edge_type = dep_type.capitalize() if dep_type else "Uses"
                if edge_type not in ["Calls", "Imports", "Inherits", "Uses", "Creates", "Reads", "Writes"]:
                    edge_type = "Uses"

                # Determine source node
                if func_name:
                    source = f"{class_name}.{func_name}" if class_name else func_name
                elif class_name:
                    source = class_name
                else:
                    source = file_path

                if target:
                    if not self.graph.has_node(target):
                        if edge_type == "Imports":
                            self.graph.add_node(target, type="Module")
                        elif edge_type == "Inherits":
                            self.graph.add_node(target, type="Class")
                        else:
                            self.graph.add_node(target, type="Function")

                    self.graph.add_edge(source, target, type=edge_type)

