class VectorStoreManager:
def search(self, query: str, top_k: int = 30) -> List[Dict[str, Any]]:
        """
        Search for top_k similar chunks.
        """
        if "e5" in self.embedding_model_name.lower():
            query_for_encode = f"query: {query}"
        else:
            query_for_encode = query

        query_vector = self.encoder.encode(query_for_encode, show_progress_bar=False).tolist()
        results = self.client.query_points(
            collection_name=self.collection_name,
            query=query_vector,
            limit=top_k
        )

        retrieved = []
        for point in results.points:
            retrieved.append({
                "content": point.payload["content"],
                "metadata": point.payload["metadata"],
                "score": point.score,
                "id": point.id
            })
        return retrieved

