elif node_type == 'call' or (language in ('javascript', 'typescript', 'tsx') and node_type == 'call_expression'):
    callee_node = node.child_by_field_name('function') if language == 'python' else (node.child_by_field_name('function') or (node.children[0] if node.children else None))
    if callee_node:
        callee_text = get_node_text(callee_node).strip()

        caller = "global"
        if function_stack:
            if class_stack:
                caller = f"{class_stack[-1]}.{function_stack[-1]}"
            else:
                caller = function_stack[-1]
        elif class_stack:
            caller = class_stack[-1]

        res["calls"].append({
            "caller": caller,
            "callee": callee_text,
            "line": start_line
        })

for child in node.children:
    traverse(child)

if pushed_class:
    class_stack.pop()
if pushed_func:
    function_stack.pop()

class VectorStoreManager:
def search(self, query: str, top_k: int = 30) -> List[Dict[str, Any]]:
        """
        Search for top_k similar chunks.
        """
        if "e5" in self.embedding_model_name.lower():
            query_for_encode = f"query: {query}"
        else:
            query_for_encode = query

        query_vector = self.encoder.encode(query_for_encode, show_progress_bar=False).tolist()
        results = self.client.query_points(
            collection_name=self.collection_name,
            query=query_vector,
            limit=top_k
        )

        retrieved = []
        for point in results.points:
            retrieved.append({
                "content": point.payload["content"],
                "metadata": point.payload["metadata"],
                "score": point.score,
                "id": point.id
            })
        return retrieved
